import * as React from 'react';
import { Slot } from '@radix-ui/react-slot';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@/lib/utils';

const buttonVariants = cva(
  'inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[var(--tei-focus-ring)] focus-visible:ring-offset-2 focus-visible:ring-offset-[var(--tei-bg)] disabled:pointer-events-none disabled:opacity-50 [&_svg]:size-4 [&_svg]:shrink-0',
  {
    variants: {
      variant: {
        default:
          'bg-[var(--tei-accent)] text-[var(--tei-accent-fg)] hover:bg-[var(--tei-accent-hover)]',
        secondary:
          'bg-[var(--tei-surface)] text-[var(--tei-text)] border border-[var(--tei-border)] hover:bg-[var(--tei-bg-secondary)]',
        ghost:
          'text-[var(--tei-text)] hover:bg-[var(--tei-bg-secondary)]',
        outline:
          'border border-[var(--tei-border)] bg-transparent text-[var(--tei-text)] hover:bg-[var(--tei-bg-secondary)]',
        destructive: 'bg-[var(--tei-danger)] text-[var(--tei-accent-fg)] hover:opacity-90',
        link: 'text-[var(--tei-text)] underline-offset-4 hover:underline',
      },
      size: {
        default: 'h-10 px-4 py-2',
        sm: 'h-8 px-3 text-xs',
        lg: 'h-11 px-6',
        icon: 'h-10 w-10',
      },
    },
    defaultVariants: { variant: 'default', size: 'default' },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : 'button';
    return (
      <Comp className={cn(buttonVariants({ variant, size }), className)} ref={ref} {...props} />
    );
  },
);
Button.displayName = 'Button';

export { buttonVariants };
